import ast, importlib.util, os, sys
from pathlib import Path

ORIG = Path("/tmp/claude-1000/-home-polaris-polaris-project/21e87760-8436-4090-870d-99ef2121882e/scratchpad/orig")
SCRIPTS = Path("/home/polaris/wt/phase-launcher/scripts")

# Load the shim's run_full_scale.py (source of truth)
spec = importlib.util.spec_from_file_location("rfs_main", SCRIPTS / "run_full_scale.py")
rfs = importlib.util.module_from_spec(spec)
spec.loader.exec_module(rfs)

def extract_env_dict(path, var_name):
    """Statically evaluate the _VNN_ENV literal from an original script."""
    tree = ast.parse(path.read_text())
    for node in ast.walk(tree):
        if isinstance(node, ast.AnnAssign) and getattr(node.target, "id", None) == var_name:
            return ast.literal_eval(node.value)
        if isinstance(node, ast.Assign):
            for t in node.targets:
                if getattr(t, "id", None) == var_name:
                    return ast.literal_eval(node.value)
    raise KeyError(var_name)

def extract_str(path, needle_prefix, group):
    """Grab out-root / banner from original via simple literal scan."""
    tree = ast.parse(path.read_text())
    found = []
    for node in ast.walk(tree):
        if isinstance(node, ast.Constant) and isinstance(node.value, str):
            found.append(node.value)
    return found

variants = ["v10","v23","v24","v25","v26","v27","v28","v29","v30_phase2"]
env_var = {v: f"_V{v[1:].upper()}_ENV" for v in variants}

results = {}
all_env_ok = True
for v in variants:
    op = ORIG / f"run_full_scale_{v}.py"
    orig_env = extract_env_dict(op, env_var[v])
    shim_env = rfs.VARIANT_ENV[v]
    env_ok = (orig_env == shim_env)
    # dict equality is order-insensitive but also verify key set + values explicitly
    keys_ok = set(orig_env) == set(shim_env) and all(orig_env[k]==shim_env[k] for k in orig_env)
    # out-root check
    orig_out = [s for s in extract_str(op,None,None) if s.startswith("outputs/full_scale")]
    orig_out = orig_out[0] if orig_out else None
    shim_out = rfs._DEFAULT_OUT_ROOT[v]
    out_ok = (orig_out == shim_out)
    results[v] = dict(env_ok=env_ok, keys_ok=keys_ok, out_ok=out_ok,
                      orig_out=orig_out, shim_out=shim_out,
                      nkeys=len(orig_env))
    if not (env_ok and keys_ok and out_ok):
        all_env_ok = False
    print(f"{v}: env_ok={env_ok} keys_ok={keys_ok} out_ok={out_ok} nkeys={len(orig_env)} out={shim_out}")

print("ALL_ENV_OUT_OK=", all_env_ok)
